mapper.select:
/* oms-master-OrCloseXct-sql-oracle.xml selectOrderCloseCenterHdList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , A.OWKEY , C.OWNM , A.CTKEY , B.CTNM , A.IODEV , A.MEDITRSN , A.MEDITCHGDATE , A.IFSYSTM , A.CRITMAXPRCSQTY , A.DELYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TORDER_MST_DDLN_CT A INNER JOIN TORDER_MST_CT B ON A.CTKEY = B.CTKEY INNER JOIN TADMIN_MST_OW C ON A.OWKEY = C.OWKEY
AND #{SEARCH_CONDITION}
ORDER BY A.UPDATEDATE DESC #{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* oms-master-OrCloseXct-sql-oracle.xml selectOrderCloseCenterDtList */ WITH L_DATE AS (
-- 월 단위 선택일 경우 SELECT TO_CHAR(TO_DATE(#{comboValue}, 'YYYYMM') + (gs.n - 1), 'YYYYMMDD') AS LDATE , #{owkey} AS OWKEY , #{ctkey} AS CTKEY FROM generate_series(1, EXTRACT(DAY FROM (DATE_TRUNC('month', TO_DATE(#{comboValue}, 'YYYYMM')) + INTERVAL '1 month - 1 day')::DATE - DATE_TRUNC('month', TO_DATE(#{comboValue}, 'YYYYMM'))::DATE + 1)::INTEGER) AS gs(n)
-- 일 단위 (오늘~7일) SELECT TO_CHAR(CURRENT_TIMESTAMP + (gs.n - 1) * INTERVAL '1 day', 'YYYYMMDD') AS LDATE , #{owkey} AS OWKEY , #{ctkey} AS CTKEY FROM generate_series(1, 7) AS gs(n)
) SELECT L_DATE.LDATE , CT.OWKEY , CT.CTKEY , (SELECT CTNM FROM TORDER_MST_CT C WHERE C.CTKEY = CT.CTKEY) AS CTNM , CT.IODEV , CA.DSBTPRCSCRITDAY , COALESCE(CA.MAXPRCSQTY, CT.CRITMAXPRCSQTY) AS MAXPRCSQTY , DA.DAYOFFHOLIYN , DA.DAYOFFHOLINM , HO.HOLINM , CA.INSERTDATE , CA.INSERTURKEY , CA.UPDATEDATE , CA.UPDATEURKEY FROM L_DATE LEFT JOIN TORDER_MST_DDLN_CT CT ON L_DATE.CTKEY = CT.CTKEY AND L_DATE.OWKEY = CT.OWKEY LEFT JOIN TORDER_INFO_CAPA_CT CA ON L_DATE.LDATE = CA.DSBTPRCSCRITDAY AND L_DATE.OWKEY = CA.OWKEY AND L_DATE.CTKEY = CA.CTKEY AND CT.IODEV = CA.IODEV LEFT JOIN TORDER_INFO_DAYOFF DA ON DA.OWKEY = CT.OWKEY AND DA.CTKEY = CT.CTKEY AND DA.DAYOFFHOLIDAY = L_DATE.LDATE LEFT JOIN TORDER_MST_HOLIDAY HO ON L_DATE.LDATE = HO.HOLIDAY WHERE 1 = 1
AND CT.OWKEY = #{owkey}
AND CT.CTKEY = #{ctkey}
AND CT.IODEV = #{iodev}
ORDER BY L_DATE.LDATE ASC

/* oms-master-OrCloseXct-sql-oracle.xml checkOrderCloseCenter */
SELECT COUNT(*)
FROM TORDER_MST_DDLN_CT
WHERE OWKEY = #{owkey}
  AND CTKEY = #{ctkey}
  AND IODEV = #{iodev}

mapper.insert:
/* oms-master-OrCloseXct-sql-oracle.xml insertOrderCloseCenter */
INSERT INTO TORDER_MST_DDLN_CT
(
	  OWKEY
	, CTKEY
	, IODEV
	, MEDITRSN
	, MEDITCHGDATE
	, IFSYSTM
	, CRITMAXPRCSQTY
	, DELYN
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY

)
VALUES (
	  #{owkey}
	, #{ctkey}
	, #{iodev}
	, #{meditrsn}
	, #{meditchgdate}
	, #{ifsystm}
	, #{critmaxprcsqty}
	, #{delyn}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.update:
/* oms-master-OrCloseXct-sql-oracle.xml updateOrderCloseCenter */
UPDATE TORDER_MST_DDLN_CT
	SET IFSYSTM            = #{ifsystm}
	  , CRITMAXPRCSQTY     = #{critmaxprcsqty}
	  , DELYN              = #{delyn}
	  , UPDATEDATE		   = #{sysdate}
	  , UPDATEURKEY 	   = #{surkey}
WHERE OWKEY = #{owkey}
  AND CTKEY = #{ctkey}
  AND IODEV = #{iodev}

/* oms-master-OrCloseXct-sql-oracle.xml mergeOrderCloseCenterCapa */
INSERT INTO TORDER_INFO_CAPA_CT (
	  OWKEY
	, CTKEY
	, IODEV
	, DSBTPRCSCRITDAY
	, MAXPRCSQTY
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{owkey}
	, #{ctkey}
	, #{iodev}
	, #{ldate}
	, #{maxprcsqty}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)
ON CONFLICT (OWKEY, CTKEY, IODEV, DSBTPRCSCRITDAY)
DO UPDATE SET
	  MAXPRCSQTY  = EXCLUDED.MAXPRCSQTY
	, UPDATEDATE  = EXCLUDED.UPDATEDATE
	, UPDATEURKEY = EXCLUDED.UPDATEURKEY

/* oms-master-OrCloseXct-sql-oracle.xml mergeOrderCloseCenterDayOff */
INSERT INTO TORDER_INFO_DAYOFF (
	  OWKEY
	, CTKEY
	, DAYOFFHOLIDAY
	, DAYOFFHOLIYN
	, DAYOFFHOLINM
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{owkey}
	, #{ctkey}
	, #{ldate}
	, #{dayoffholiyn}
	, #{dayoffholinm}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)
ON CONFLICT (OWKEY, CTKEY, DAYOFFHOLIDAY)
DO UPDATE SET
	  DAYOFFHOLIYN  = EXCLUDED.DAYOFFHOLIYN
	, DAYOFFHOLINM  = EXCLUDED.DAYOFFHOLINM
	, UPDATEDATE    = EXCLUDED.UPDATEDATE
	, UPDATEURKEY   = EXCLUDED.UPDATEURKEY

